import json
with open('baseline-packages.json') as f: baseline = json.load(f)
with open('after-cpm-packages.json') as f: after = json.load(f)

def get_pkgs(data):
    result = {}
    for proj in data['projects']:
        name = proj['path'].split('/')[-2]
        for fw in proj['frameworks']:
            for pkg in fw['topLevelPackages']:
                result.setdefault(name, []).append((pkg['id'], pkg['resolvedVersion']))
    return result

b = get_pkgs(baseline)
a = get_pkgs(after)
print('Baseline == After?', b == a)
for proj in sorted(set(list(b.keys()) + list(a.keys()))):
    bp = set(b.get(proj, []))
    ap = set(a.get(proj, []))
    if bp != ap:
        print(f'  DIFF in {proj}: baseline={bp-ap}, after={ap-bp}')
    else:
        print(f'  {proj}: identical')
"

